/**
 * speak — Hebrew TTS with pre-recorded voice file priority.
 *
 * Priority:
 *   1. Pre-recorded MP3 from /audio/voices/ (generated by scripts/generate-audio.py)
 *   2. Browser Web Speech API (he-IL) as fallback
 *
 * Voice modes (used for Web Speech fallback):
 *   "instruction"   — rate 0.78, pitch 1.05
 *   "letter"        — rate 0.68, pitch 1.08  (slowest — isolated pronunciation)
 *   "number"        — rate 0.70, pitch 1.06
 *   "encouragement" — rate 0.88, pitch 1.12  (warm, upbeat)
 *   "syllable"      — rate 0.62, pitch 1.05  (very slow — hear each part)
 */

export type VoiceMode = "instruction" | "letter" | "number" | "encouragement" | "syllable";

const VOICE_CONFIG: Record<VoiceMode, { rate: number; pitch: number }> = {
  instruction:   { rate: 0.78, pitch: 1.05 },
  letter:        { rate: 0.68, pitch: 1.08 },
  number:        { rate: 0.70, pitch: 1.06 },
  encouragement: { rate: 0.88, pitch: 1.12 },
  syllable:      { rate: 0.62, pitch: 1.05 },
};

