// ── Audio element pool (for overlapping / instant playback) ──────────────────

let currentVoice: HTMLAudioElement | null = null;

function playVoiceFile(filename: string): void {
  try {
    if (currentVoice) {
      currentVoice.pause();
      currentVoice.currentTime = 0;
    }
    const audio = new Audio(`/audio/voices/${filename}`);
    audio.volume = 1.0;
    audio.play().catch(() => {/* autoplay blocked */});
    currentVoice = audio;
  } catch {/* silent */}
}

// ── Web Speech API fallback ───────────────────────────────────────────────────

let _cachedVoice: SpeechSynthesisVoice | null | undefined = undefined;

function getHebrewVoice(): SpeechSynthesisVoice | null {
  if (_cachedVoice !== undefined) return _cachedVoice;
  const voices = window.speechSynthesis?.getVoices() ?? [];
  _cachedVoice =
    voices.find(v => v.lang === "he-IL") ??
    voices.find(v => v.lang.startsWith("he")) ??
    null;
  return _cachedVoice;
}

if (typeof window !== "undefined" && "speechSynthesis" in window) {
  window.speechSynthesis.onvoiceschanged = () => {
    _cachedVoice = undefined;
    getHebrewVoice();
  };
}

function speakTTS(text: string, mode: VoiceMode): void {
  if (!("speechSynthesis" in window)) return;
  window.speechSynthesis.cancel();
  const { rate, pitch } = VOICE_CONFIG[mode];
  const u   = new SpeechSynthesisUtterance(text);
  u.lang    = "he-IL";
  u.rate    = rate;
  u.pitch   = pitch;
  u.volume  = 1.0;
  const voice = getHebrewVoice();
  if (voice) u.voice = voice;
  window.speechSynthesis.speak(u);
}

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * speak — plays a pre-recorded voice file if available, otherwise uses TTS.
 */
export function speak(text: string, mode: VoiceMode = "instruction"): void {
  // Strip emoji / punctuation variants for lookup
  const clean = text.trim();
  const file  = VOICE_FILES[clean];
  if (file) {
    playVoiceFile(file);
    return;
  }
  speakTTS(text, mode);
}

/** Stop any in-progress speech. */
export function stopSpeech(): void {
  currentVoice?.pause();
  currentVoice = null;
  window.speechSynthesis?.cancel();
}

